1	import { Theme } from '../common/Theme';
2	
3	@Component
4	export struct EmptyStateView {
5	  @Prop title: string = '暂无数据';
6	  @Prop subtitle: string = '';
7	
8	  build() {
9	    Column({ space: 8 }) {
10	      Text(this.title)
11	        .fontSize(16)
12	        .fontWeight(FontWeight.Medium)
13	        .fontColor(Theme.textTertiary)
14	      if (this.subtitle) {
15	        Text(this.subtitle)
16	          .fontSize(14)
17	          .fontColor(Theme.textQuaternary)
18	      }
19	    }
20	    .width('100%')
21	    .padding({ top: 32, bottom: 32 })
22	    .justifyContent(FlexAlign.Center)
23	    .alignItems(HorizontalAlign.Center)
24	  }
25	}
26	
27	@Component
28	export struct SectionTitle {
29	  @Prop title: string = '';
30	
31	  build() {
32	    Text(this.title)
33	      .fontSize(16)
34	      .fontWeight(FontWeight.SemiBold)
35	      .fontColor(Theme.textPrimary)
36	      .width('100%')
37	  }
38	}
39	
40	@Component
41	export struct PrimaryButton {
42	  @Prop label: string = '保存';
43	  @Prop enabled: boolean = true;
44	  onClick?: () => void;
45	
46	  build() {
47	    Button(this.label)
48	      .width('100%')
49	      .height(48)
50	      .fontSize(16)
51	      .fontWeight(FontWeight.SemiBold)
52	      .fontColor(Theme.textOnBrand)
53	      .backgroundColor(Theme.brandPrimary)
54	      .borderRadius(Theme.radiusButton)
55	      .shadow(this.enabled ? Theme.buttonShadow : { radius: 0, color: Color.Transparent, offsetY: 0 })
56	      .enabled(this.enabled)
57	      .onClick(() => {
58	        if (this.onClick) {
59	          this.onClick();
60	        }
61	      })
62	  }
63	}
64	
