1	import { Theme, BrandGradient } from '../common/Theme';
2	import { InspectionController } from '../controllers/InspectionController';
3	import { Inspection, InspectionCheckItem, CheckResult } from '../model/Inspection';
4	import { PageHeader, FormField, PrimaryButton, DangerButton, GhostButton } from '../components/CommonUi';
5	import { formatDate, parseDate } from '../services/IdGenerator';
6	import { promptAction } from '@kit.ArkUI';
7	
8	@Component
9	export struct InspectionDetailPage {
10	  inspectionId: string = '';
11	  onBack?: () => void;
12	  onOpenHazard?: (id: string) => void;
13	  @State draft: Inspection = new Inspection();
14	  @State selectedCheckId: string = '';
15	  private controller = new InspectionController();
16	
17	  aboutToAppear(): void {
18	    if (this.inspectionId) {
19	      const found = this.controller.get(this.inspectionId);
20	      this.draft = found ? new Inspection(found) : this.controller.createDraft();
21	    } else {
22	      this.draft = this.controller.createDraft();
23	    }
24	  }
25	
26	  private save(): void {
27	    this.controller.save(this.draft);
28	    promptAction.showToast({ message: '已保存' });
29	    if (this.onBack) this.onBack();
30	  }
31	
32	  private delete(): void {
33	    if (this.inspectionId) {
34	      this.controller.delete(this.inspectionId);
35	      if (this.onBack) this.onBack();
36	    }
37	  }
38	
39	  private markNormal(item: InspectionCheckItem): void {
40	    item.result = CheckResult.NORMAL;
41	    this.selectedCheckId = '';
42	    this.draft = new Inspection(this.draft);
43	  }
44	
45	  private markAbnormal(item: InspectionCheckItem): void {
46	    item.result = CheckResult.ABNORMAL;
47	    this.selectedCheckId = item.id;
48	    this.draft = new Inspection(this.draft);
49	  }
50	
51	  private convertToHazard(): void {
52	    const hazard = this.controller.convertToHazard(this.draft);
53	    promptAction.showToast({ message: '已转为隐患' });
54	    if (this.onOpenHazard) this.onOpenHazard(hazard.id);
55	  }
56	
57	  private hasAbnormal(): boolean {
58	    return this.draft.checklist.some(ci => ci.result === CheckResult.ABNORMAL);
59	  }
60	
61	  build() {
62	    Column({ space: 0 }) {
63	      PageHeader({
64	        title: this.inspectionId ? '巡检详情' : '新建巡检',
65	        onBack: () => {
66	          if (this.onBack) this.onBack();
67	        },
68	        trailing: this.saveButton
69	      })
70	
71	      Scroll() {
72	        Column({ space: 16 }) {
73	          Column({ space: 16 }) {
74	            FormField({
75	              label: '巡检标题',
76	              placeholder: '请输入巡检标题',
77	              value: this.draft.title,
78	              componentId: 'inspection-detail-title-input',
79	              onChange: (v) => this.draft.title = v
80	            })
81	            FormField({
82	              label: '巡检地点',
83	              placeholder: '请输入地点',
84	              value: this.draft.location,
85	              componentId: 'inspection-detail-location-input',
86	              onChange: (v) => this.draft.location = v
87	            })
88	            Column({ space: 6 }) {
89	              Text('巡检日期')
90	                .fontSize(14)
91	                .fontWeight(FontWeight.Medium)
92	                .fontColor(Theme.textSecondary)
93	                .width('100%')
94	              TextInput({ text: formatDate(this.draft.date), placeholder: '选择日期' })
95	                .id('inspection-detail-date-picker')
96	                .width('100%')
97	                .height(48)
98	                .fontSize(14)
99	                .fontColor(Theme.textPrimary)
100	                .placeholderColor(Theme.textPlaceholder)
101	                .backgroundColor(Theme.inputBg)
102	                .border({ width: 1, color: Theme.borderDefault })
103	                .borderRadius(Theme.radiusPill)
104	                .padding({ left: 14, right: 14 })
105	                .onChange((v) => {
106	                  const ts = parseDate(v);
107	                  if (ts !== null) this.draft.date = ts;
108	                })
109	            }
110	            .width('100%')
111	            .alignItems(HorizontalAlign.Start)
112	          }
113	          .width('100%')
114	          .padding(16)
115	          .backgroundColor(Theme.cardBg)
116	          .borderRadius(Theme.radiusCard)
117	          .shadow(Theme.cardShadow)
118	
119	          Column({ space: 12 }) {
120	            Text('检查项')
121	              .fontSize(16)
122	              .fontWeight(FontWeight.SemiBold)
123	              .fontColor(Theme.textPrimary)
124	              .width('100%')
125	
126	            List({ space: 12 }) {
127	              ForEach(this.draft.checklist, (item: InspectionCheckItem, index: number) => {
128	                ListItem() {
129	                  this.CheckItemRow(item, index)
130	                }
131	              }, (item: InspectionCheckItem) => item.id)
132	            }
133	            .id('inspection-detail-checklist')
134	            .width('100%')
135	
136	            if (this.hasAbnormal()) {
137	              Button('将异常项转为隐患')
138	                .id('inspection-detail-convert-hazard-button')
139	                .width('100%')
140	                .height(44)
141	                .fontSize(14)
142	                .fontWeight(FontWeight.Medium)
143	                .fontColor(Theme.danger)
144	                .backgroundColor(Theme.dangerSoft)
145	                .borderRadius(Theme.radiusButton)
146	                .onClick(() => this.convertToHazard())
147	            }
148	          }
149	          .width('100%')
150	          .padding(16)
151	          .backgroundColor(Theme.cardBg)
152	          .borderRadius(Theme.radiusCard)
153	          .shadow(Theme.cardShadow)
154	
155	          if (this.inspectionId) {
156	            DangerButton({
157	              label: '删除巡检',
158	              onClick: () => this.delete()
159	            })
160	          }
161	
162	          Blank().height(24)
163	        }
164	        .width('100%')
165	        .padding(16)
166	        .padding({ bottom: 24 })
167	      }
168	      .width('100%')
169	      .layoutWeight(1)
170	      .scrollBar(BarState.Off)
171	
172	      Column() {
173	        PrimaryButton({
174	          id: 'inspection-detail-submit-button',
175	          label: '提交巡检结果',
176	          onClick: () => this.save()
177	        })
178	      }
179	      .width('100%')
180	      .padding(16)
181	      .backgroundColor(Theme.pageBg)
182	    }
183	    .width('100%')
184	    .height('100%')
185	    .backgroundColor(Theme.pageBg)
186	  }
187	
188	  @Builder
189	  saveButton() {
190	    Button('保存')
191	      .fontSize(14)
192	      .fontWeight(FontWeight.SemiBold)
193	      .fontColor(Theme.brandPrimary)
194	      .backgroundColor(Color.Transparent)
195	      .onClick(() => this.save())
196	  }
197	
198	  @Builder
199	  CheckItemRow(item: InspectionCheckItem, index: number) {
200	    Column({ space: 12 }) {
201	      Row({ space: 12 }) {
