365	  private isActiveStatus(status: HazardStatus): boolean {
366	    return this.draft.status === status;
367	  }
368	
369	  private isCompletedStatus(status: HazardStatus): boolean {
370	    const idx = STATUS_OPTIONS.indexOf(status);
371	    const current = STATUS_OPTIONS.indexOf(this.draft.status);
372	    return idx < current;
373	  }
